<?php

class Links_Asset_Map
{
    private static $map = array (
  'Links.css' => '',
  'Links.js' => '',
  'LinksAdminConfig.css' => '',
  'LinksAdminConfig.js' => '',
  'LinksAdminManage.css' => '',
  'LinksAdminManage.js' => '',
);

    public static function get($name)
    {
        if (!isset(self::$map[$name])) {
            return null;
        }

        return base64_decode(self::$map[$name]);
    }
}